import { useState, useEffect } from 'react';
import axios from 'axios';
import { Trash2, Edit, Plus, X, Check } from 'lucide-react';

export default function CourseManager() {
    const [courses, setCourses] = useState([]);
    const [centers, setCenters] = useState([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [currentCourse, setCurrentCourse] = useState(null);
    const [user, setUser] = useState(null);
    const [formData, setFormData] = useState({
        title: '',
        subject: '',
        board: 'CBSE',
        mode: 'Online',
        price: '',
        duration: '',
        description: '',
        centerId: '',
        staffId: '',
    });
    const [staff, setStaff] = useState([]);

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) setUser(JSON.parse(storedUser));
        fetchCourses();
        fetchCenters();
        fetchStaff();
    }, []);

    const getAuthHeader = () => {
        const token = localStorage.getItem('token');
        return { headers: { Authorization: `Bearer ${token}` } };
    };

    const fetchCourses = async () => {
        try {
            const res = await axios.get('/courses');
            if (Array.isArray(res.data)) {
                setCourses(res.data);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const fetchCenters = async () => {
        try {
            const res = await axios.get('/centers');
            if (Array.isArray(res.data)) {
                setCenters(res.data);
            }
        } catch (err) {
            console.error("Failed to fetch centers", err);
        }
    }

    const fetchStaff = async () => {
        try {
            const token = localStorage.getItem('token');
            const res = await axios.get('/users', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (Array.isArray(res.data)) {
                setStaff(res.data.filter(u => u.role === 'staff' && u.status === 'active'));
            }
        } catch (err) {
            console.error("Failed to fetch staff", err);
        }
    };

    const handleDelete = async (id) => {
        if (confirm('Are you sure you want to delete this course?')) {
            try {
                await axios.delete(`/courses/${id}`, getAuthHeader());
                fetchCourses();
            } catch (err) {
                alert('Failed to delete course');
            }
        }
    };

    const handleEdit = (course) => {
        setCurrentCourse(course);
        setFormData({
            title: course.title,
            subject: course.subject,
            board: course.board,
            mode: course.mode,
            price: course.price || '',
            duration: course.duration || '',
            description: course.description || '',
            thumbnail: course.thumbnail || '',
            centerId: course.centerId || (centers.length > 0 ? centers[0].id : ''),
            staffId: course.staffId || '',
        });
        setIsModalOpen(true);
    };

    const handleAdd = () => {
        setCurrentCourse(null);
        setFormData({
            title: '',
            subject: '',
            board: 'CBSE',
            mode: 'Online',
            price: '',
            duration: '',
            description: '',
            thumbnail: '',
            centerId: centers.length > 0 ? centers[0].id : '',
            staffId: '',
        });
        setIsModalOpen(true);
    };

    const [uploading, setUploading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.centerId && centers.length === 0) {
            alert("No centers available to assign course to.");
            return;
        }

        let thumbnailUrl = formData.thumbnail;

        // Handle Image Upload if file selected
        if (formData.file) {
            setUploading(true);
            const uploadData = new FormData();
            uploadData.append('image', formData.file);
            const token = localStorage.getItem('token');
            try {
                const uploadRes = await axios.post('/upload', uploadData, {
                    headers: { 'Content-Type': 'multipart/form-data', Authorization: `Bearer ${token}` }
                });
                thumbnailUrl = uploadRes.data;
            } catch (err) {
                alert('Failed to upload image');
                setUploading(false);
                return;
            }
            setUploading(false);
        }

        const dataToSend = {
            ...formData,
            thumbnail: thumbnailUrl,
            centerId: formData.centerId || (centers[0]?.id)
        };
        // Remove file object before sending to API
        delete dataToSend.file;

        try {
            if (currentCourse) {
                await axios.put(`/courses/${currentCourse.id}`, dataToSend, getAuthHeader());
            } else {
                await axios.post('/courses', dataToSend, getAuthHeader());
            }
            setIsModalOpen(false);
            fetchCourses();
        } catch (err) {
            console.error(err);
            alert('Failed to save course: ' + (err.response?.data?.message || err.message));
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold">Manage Courses</h2>
                {user?.role === 'admin' && (
                    <button onClick={handleAdd} className="bg-green-600 text-white px-4 py-2 rounded flex items-center gap-2 hover:bg-green-700">
                        <Plus size={20} /> Add Course
                    </button>
                )}
            </div>

            <div className="bg-white rounded-lg shadow overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-100 border-b">
                        <tr>
                            <th className="p-4">Title</th>
                            <th className="p-4">Subject</th>
                            <th className="p-4">Board</th>
                            <th className="p-4">Mode</th>
                            {user?.role === 'admin' && <th className="p-4">Actions</th>}
                        </tr>
                    </thead>
                    <tbody>
                        {(Array.isArray(courses) ? courses : []).map((course) => (
                            <tr key={course.id} className="border-b hover:bg-gray-50">
                                <td className="p-4 font-medium">{course.title}</td>
                                <td className="p-4">{course.subject}</td>
                                <td className="p-4">{course.board}</td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-bold ${course.mode === 'Online' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'}`}>
                                        {course.mode}
                                    </span>
                                </td>
                                {user?.role === 'admin' && (
                                    <td className="p-4 flex gap-3">
                                        <button onClick={() => handleEdit(course)} className="text-blue-600 hover:text-blue-800"><Edit size={18} /></button>
                                        <button onClick={() => handleDelete(course.id)} className="text-red-600 hover:text-red-800"><Trash2 size={18} /></button>
                                    </td>
                                )}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white p-6 rounded-lg w-full max-w-md max-h-[90vh] overflow-y-auto">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-xl font-bold">{currentCourse ? 'Edit Course' : 'Add Course'}</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-black"><X size={24} /></button>
                        </div>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <input type="text" placeholder="Course Title" required className="w-full p-2 border rounded" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />

                            {/* Thumbnail Upload */}
                            <div>
                                <label className="block text-sm font-medium mb-1">Course Thumbnail</label>
                                <input
                                    type="file"
                                    accept="image/*"
                                    className="w-full p-2 border rounded bg-gray-50"
                                    onChange={e => setFormData({ ...formData, file: e.target.files[0] })}
                                />
                                {formData.thumbnail && !formData.file && (
                                    <div className="mt-2 text-xs text-gray-500">Current: {formData.thumbnail}</div>
                                )}
                            </div>

                            {/* Center Selection */}
                            <div>
                                <label className="block text-sm font-medium mb-1">Center</label>
                                <select className="w-full p-2 border rounded" value={formData.centerId} onChange={e => setFormData({ ...formData, centerId: e.target.value })} required>
                                    <option value="">Select Center</option>
                                    {(Array.isArray(centers) ? centers : []).map(center => (
                                        <option key={center.id} value={center.id}>{center.name}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Instructor Selection */}
                            <div>
                                <label className="block text-sm font-medium mb-1">Instructor (Optional)</label>
                                <select className="w-full p-2 border rounded" value={formData.staffId} onChange={e => setFormData({ ...formData, staffId: e.target.value })}>
                                    <option value="">Unassigned</option>
                                    {staff.map(s => (
                                        <option key={s.id} value={s.id}>{s.name} ({s.specialization || 'No Specialization'})</option>
                                    ))}
                                </select>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <input type="text" placeholder="Subject" required className="w-full p-2 border rounded" value={formData.subject} onChange={e => setFormData({ ...formData, subject: e.target.value })} />
                                <input type="number" placeholder="Price (₹)" className="w-full p-2 border rounded" value={formData.price} onChange={e => setFormData({ ...formData, price: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium mb-1">Duration (Minutes)</label>
                                <input
                                    type="number"
                                    placeholder="e.g., 60 (Leave empty for Lifetime)"
                                    className="w-full p-2 border rounded"
                                    value={formData.duration}
                                    onChange={e => setFormData({ ...formData, duration: e.target.value })}
                                />
                                <p className="text-xs text-gray-500 mt-1">Set to <b>60</b> for 1 hour access. Users can repurchase after expiry.</p>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <select className="w-full p-2 border rounded" value={formData.board} onChange={e => setFormData({ ...formData, board: e.target.value })}>
                                    <option value="CBSE">CBSE</option>
                                    <option value="ICSE">ICSE</option>
                                    <option value="TN">State Board</option>
                                    <option value="Other">Other</option>
                                </select>
                                <select className="w-full p-2 border rounded" value={formData.mode} onChange={e => setFormData({ ...formData, mode: e.target.value })}>
                                    <option value="online">Online</option>
                                    <option value="offline">Offline</option>
                                </select>
                            </div>
                            <textarea placeholder="Description" className="w-full p-2 border rounded h-24" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })}></textarea>
                            <button type="submit" className="w-full bg-blue-600 text-white py-2 rounded font-bold hover:bg-blue-700">Save Course</button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import axios from 'axios';
import { Trash2, Upload, Image as ImageIcon } from 'lucide-react';

export default function GalleryManager() {
    const [photos, setPhotos] = useState([]);
    const [file, setFile] = useState(null);
    const [title, setTitle] = useState('');
    const [uploading, setUploading] = useState(false);
    const [user, setUser] = useState(null);

    const [activeTab, setActiveTab] = useState('all');
    const [category, setCategory] = useState('miscellaneous');

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) setUser(JSON.parse(storedUser));
        fetchPhotos();
    }, []);

    const fetchPhotos = async () => {
        try {
            const res = await axios.get('/gallery');
            if (Array.isArray(res.data)) {
                setPhotos(res.data);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const getAuthHeader = () => {
        const token = localStorage.getItem('token');
        return { headers: { Authorization: `Bearer ${token}` } };
    };

    // Filter photos based on active tab
    const filteredPhotos = activeTab === 'all'
        ? (Array.isArray(photos) ? photos : [])
        : (Array.isArray(photos) ? photos : []).filter(p => p.category === activeTab);

    const handleDelete = async (id) => {
        if (confirm('Delete this photo?')) {
            try {
                await axios.delete(`/gallery/${id}`, getAuthHeader());
                fetchPhotos();
            } catch (err) {
                alert('Failed to delete photo');
            }
        }
    };

    const handleUpload = async (e) => {
        e.preventDefault();
        if (!file) return;

        setUploading(true);
        const formData = new FormData();
        formData.append('image', file);
        const token = localStorage.getItem('token');

        try {
            // 1. Upload Image
            const uploadRes = await axios.post('/upload', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                    Authorization: `Bearer ${token}`
                },
            });
            const imageUrl = uploadRes.data;

            // 2. Save to Gallery
            await axios.post('/gallery', { title, imageUrl, category }, getAuthHeader());

            setFile(null);
            setTitle('');
            setCategory('miscellaneous');
            fetchPhotos();
        } catch (err) {
            alert('Upload failed');
        } finally {
            setUploading(false);
        }
    };

    const categories = ['event', 'facility', 'miscellaneous'];

    return (
        <div>
            <h2 className="text-2xl font-bold mb-6">Photo Gallery</h2>

            {/* Category Tabs */}
            <div className="flex gap-4 mb-8 border-b">
                <button
                    onClick={() => setActiveTab('all')}
                    className={`pb-2 px-4 font-medium capitalize ${activeTab === 'all' ? 'border-b-2 border-blue-600 text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    All
                </button>
                {categories.map(cat => (
                    <button
                        key={cat}
                        onClick={() => setActiveTab(cat)}
                        className={`pb-2 px-4 font-medium capitalize ${activeTab === cat ? 'border-b-2 border-blue-600 text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        {cat}
                    </button>
                ))}
            </div>

            {/* Upload Section */}
            {user?.role === 'admin' && (
                <div className="bg-white p-6 rounded-lg shadow mb-8">
                    <h3 className="font-bold mb-4 flex items-center gap-2"><Upload size={20} /> Upload New Photo</h3>
                    <form onSubmit={handleUpload} className="flex flex-col md:flex-row gap-4 items-end">
                        <div className="flex-1 w-full">
                            <label className="block text-sm font-medium mb-1">Photo Title</label>
                            <input
                                type="text"
                                className="w-full p-2 border rounded"
                                value={title}
                                onChange={e => setTitle(e.target.value)}
                                placeholder="e.g., Annual Sports Day"
                            />
                        </div>
                        <div className="flex-1 w-full">
                            <label className="block text-sm font-medium mb-1">Category</label>
                            <select
                                className="w-full p-2 border rounded"
                                value={category}
                                onChange={e => setCategory(e.target.value)}
                            >
                                {categories.map(cat => (
                                    <option key={cat} value={cat} className="capitalize">{cat}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex-1 w-full">
                            <label className="block text-sm font-medium mb-1">Select Image</label>
                            <input
                                type="file"
                                className="w-full p-2 border rounded bg-gray-50"
                                onChange={e => setFile(e.target.files[0])}
                                accept="image/*"
                                required
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={uploading}
                            className="bg-blue-600 text-white px-6 py-2.5 rounded font-bold hover:bg-blue-700 disabled:opacity-50 w-full md:w-auto"
                        >
                            {uploading ? 'Uploading...' : 'Upload'}
                        </button>
                    </form>
                </div>
            )}

            {/* Grid View */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {filteredPhotos.map((photo) => (
                    <div key={photo.id} className="relative group bg-white rounded-lg shadow overflow-hidden">
                        <img
                            src={`http://localhost:5000${photo.imageUrl}`}
                            alt={photo.title}
                            className="w-full h-40 object-cover"
                        />
                        <div className="p-2">
                            <p className="font-medium text-sm truncate">{photo.title || 'Untitled'}</p>
                            <span className="text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full capitalize">{photo.category}</span>
                        </div>
                        {user?.role === 'admin' && (
                            <button
                                onClick={() => handleDelete(photo.id)}
                                className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition hover:bg-red-700"
                            >
                                <Trash2 size={16} />
                            </button>
                        )}
                    </div>
                ))}
                {filteredPhotos.length === 0 && (
                    <div className="col-span-full text-center py-12 text-gray-500">
                        No photos found in this category.
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import axios from 'axios';
import { CreditCard, Trash2, AlertTriangle, X, Loader, Printer } from 'lucide-react'; // Added Loader, X, AlertTriangle, Printer
import { useToast } from '../../components/ui/Toast'; // Import Toast

export default function PaymentManager() {
    const [payments, setPayments] = useState([]);
    const [loading, setLoading] = useState(false);

    // Deletion State
    const [deleteModalOpen, setDeleteModalOpen] = useState(false);
    const [paymentToDelete, setPaymentToDelete] = useState(null);
    const [isDeleting, setIsDeleting] = useState(false);

    const { addToast } = useToast();

    useEffect(() => {
        fetchPayments();
    }, []);

    const fetchPayments = async () => {
        try {
            setLoading(true);
            const token = localStorage.getItem('token');
            const res = await axios.get('/payments', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (Array.isArray(res.data)) {
                setPayments(res.data);
            }
            setLoading(false);
            setLoading(false);
        } catch (err) {
            console.error("Fetch Payment Error:", err);
            const msg = err.response?.data?.message || err.message;
            const status = err.response?.status;
            addToast(`Failed to fetch payments: ${msg} (${status})`, "error");
            setLoading(false);
        }
    };

    const confirmDelete = (payment) => {
        console.log("Requesting delete for payment:", payment); // DEBUG: Check what we are trying to delete
        setPaymentToDelete(payment);
        setDeleteModalOpen(true);
    };

    const handleDelete = async () => {
        if (!paymentToDelete) return;

        setIsDeleting(true);
        console.log("Deleting Payment ID:", paymentToDelete.id); // DEBUG: Log the ID being sent

        try {
            const token = localStorage.getItem('token');
            if (!paymentToDelete.id) {
                throw new Error("Payment ID is missing in frontend object");
            }

            await axios.delete(`/payments/${paymentToDelete.id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });

            addToast("Transaction deleted successfully", "success");
            fetchPayments(); // Refresh list
            setDeleteModalOpen(false);
        } catch (err) {
            console.error("Delete Error:", err);
            const msg = err.response?.data?.message || err.message;
            const detail = err.response?.data?.error?.parent?.sqlMessage || '';
            const status = err.response?.status;

            addToast(`Failed to delete: ${msg} (Status: ${status})`, "error");
            alert(`Debug Info:\nStatus: ${status}\nMessage: ${msg}\nDetail: ${detail}\nID Sent: ${paymentToDelete.id}`);
        } finally {
            setIsDeleting(false);
            setPaymentToDelete(null);
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Transaction History</h2>
                <div className="relative">
                    <input
                        type="text"
                        placeholder="Search by ID or Student..."
                        className="pl-4 pr-10 py-2 border rounded-lg w-72 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition"
                        onChange={(e) => {
                            const term = e.target.value.toLowerCase();
                            const rows = document.querySelectorAll('tbody tr');
                            rows.forEach(row => {
                                const text = row.innerText.toLowerCase();
                                row.style.display = text.includes(term) ? '' : 'none';
                            });
                        }}
                    />
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b">
                            <tr>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Date</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Student</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Course</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Amount</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Method</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Transaction ID</th>
                                <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Status</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {(Array.isArray(payments) ? payments : []).map((payment) => (
                                <tr key={payment.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="p-4 text-sm text-gray-600">
                                        <div className="font-medium">{new Date(payment.createdAt).toLocaleDateString()}</div>
                                        <div className="text-xs text-gray-400">{new Date(payment.createdAt).toLocaleTimeString()}</div>
                                    </td>
                                    <td className="p-4">
                                        <div className="font-medium text-gray-900">{payment.User?.name || 'Unknown'}</div>
                                        <div className="text-xs text-gray-500">{payment.User?.email}</div>
                                    </td>
                                    <td className="p-4 text-sm text-gray-700">{payment.Course?.title || 'Deleted Course'}</td>
                                    <td className="p-4 font-bold text-emerald-600">₹{payment.amount}</td>
                                    <td className="p-4 text-sm text-gray-600">
                                        <span className="flex items-center gap-1">
                                            {payment.method === 'Credit Card' ? <CreditCard size={14} /> : 'UPI'}
                                            {payment.method}
                                        </span>
                                    </td>
                                    <td className="p-4">
                                        <span className="font-mono text-xs bg-gray-100 px-2 py-1 rounded text-gray-600 select-all">
                                            {payment.transactionId}
                                        </span>
                                    </td>
                                    <td className="p-4 flex items-center gap-3">
                                        <div className="flex items-center gap-2">
                                            <button
                                                onClick={() => window.open(`/invoice/${payment.id}`, '_blank')}
                                                className="p-2 text-blue-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-all"
                                                title="View Invoice"
                                            >
                                                <Printer size={18} />
                                            </button>
                                            <button
                                                onClick={() => confirmDelete(payment)}
                                                className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all"
                                                title="Delete Transaction"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {payments.length === 0 && !loading && (
                                <tr><td colSpan="7" className="p-12 text-center text-gray-500">No transactions found.</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Custom Delete Modal */}
            {deleteModalOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm p-6 transform transition-all scale-100">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                                <AlertTriangle className="text-red-500" />
                                Confirm Deletion
                            </h3>
                            <button onClick={() => setDeleteModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <X size={20} />
                            </button>
                        </div>

                        <div className="mb-8">
                            <p className="text-gray-600 mb-2">Are you sure you want to delete this transaction?</p>
                            <div className="bg-red-50 p-3 rounded-lg border border-red-100 text-sm text-red-800">
                                <p><strong>ID:</strong> {paymentToDelete?.transactionId}</p>
                                <p><strong>Amount:</strong> ₹{paymentToDelete?.amount}</p>
                            </div>
                            <p className="text-xs text-gray-400 mt-2">This action cannot be undone.</p>
                        </div>

                        <div className="flex gap-3">
                            <button
                                onClick={() => setDeleteModalOpen(false)}
                                className="flex-1 py-2.5 border border-gray-300 rounded-lg font-medium text-gray-700 hover:bg-gray-50 transition"
                                disabled={isDeleting}
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleDelete}
                                className="flex-1 py-2.5 bg-red-600 text-white rounded-lg font-bold hover:bg-red-700 transition flex justify-center items-center gap-2"
                                disabled={isDeleting}
                            >
                                {isDeleting ? <Loader className="animate-spin" size={18} /> : 'Delete Permanently'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import axios from 'axios';
import { Trash2, Shield, User, Edit } from 'lucide-react';

export default function UserManager({ role }) {
    const [users, setUsers] = useState([]);

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchUsers();
    }, [role]);

    const fetchUsers = async () => {
        setLoading(true);
        setError('');
        try {
            const url = role ? `/users?role=${role}` : '/users';
            console.log(`[DEBUG] Fetching users from ${url}`);
            const token = localStorage.getItem('token');
            const res = await axios.get(url, {
                headers: { Authorization: `Bearer ${token}` }
            });
            console.log(`[DEBUG] Users received:`, res.data);
            if (Array.isArray(res.data)) {
                setUsers(res.data);
            }
        } catch (err) {
            console.error(err);
            setError(err.response?.data?.message || err.message || 'Failed to fetch users');
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id) => {
        if (confirm('Are you sure you want to delete this user?')) {
            try {
                const token = localStorage.getItem('token');
                await axios.delete(`/users/${id}`, { headers: { Authorization: `Bearer ${token}` } });
                fetchUsers();
            } catch (err) {
                const message = err.response?.data?.message || 'Failed to delete user';
                alert(message);
            }
        }
    };


    const [isModalOpen, setIsModalOpen] = useState(false);
    const [currentUser, setCurrentUser] = useState(null);
    const [uploading, setUploading] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        qualification: '',
        profileImage: '',
    });

    const handleEdit = (user) => {
        setCurrentUser(user);
        setFormData({
            name: user.name,
            qualification: user.qualification || '',
            profileImage: user.profileImage || '',
        });
        setIsModalOpen(true);
    };

    const handleUpdate = async (e) => {
        e.preventDefault();
        setUploading(true);
        let profileImageUrl = formData.profileImage;

        // Handle Image Upload
        if (formData.file) {
            const uploadData = new FormData();
            uploadData.append('image', formData.file);
            const token = localStorage.getItem('token');
            try {
                const uploadRes = await axios.post('/upload', uploadData, {
                    headers: { 'Content-Type': 'multipart/form-data', Authorization: `Bearer ${token}` }
                });
                profileImageUrl = uploadRes.data;
            } catch (err) {
                alert('Failed to upload image');
                setUploading(false);
                return;
            }
        }

        try {
            const token = localStorage.getItem('token');
            const dataToSend = {
                ...formData,
                profileImage: profileImageUrl
            };
            delete dataToSend.file;

            await axios.put(`/users/${currentUser.id}`, dataToSend, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setIsModalOpen(false);
            fetchUsers();
        } catch (err) {
            alert('Failed to update user');
        } finally {
            setUploading(false);
        }
    };

    if (loading) return <div className="p-8 text-center text-gray-500">Loading users...</div>;
    if (error) return (
        <div className="p-8 text-center">
            <div className="text-red-500 mb-2">Error: {error}</div>
            <button onClick={fetchUsers} className="bg-blue-600 text-white px-4 py-2 rounded">Retry</button>
        </div>
    );

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold capitalize">{role || 'All'} Users</h2>
                <div className="bg-blue-100 text-blue-800 px-4 py-2 rounded-lg font-bold">
                    Total: {users.length}
                </div>
            </div>

            <div className="bg-white rounded-lg shadow overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-100 border-b">
                        <tr>
                            <th className="p-4">Name</th>
                            <th className="p-4">Email</th>
                            {!role && <th className="p-4">Role</th>}
                            <th className="p-4">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {(Array.isArray(users) ? users : []).map((user) => (
                            <tr key={user.id} className="border-b hover:bg-gray-50">
                                <td className="p-4 font-medium flex items-center gap-3">
                                    {user.profileImage ? (
                                        <img src={`http://localhost:5000${user.profileImage}`} alt={user.name} className="w-10 h-10 rounded-full object-cover" />
                                    ) : (
                                        <div className="bg-gray-200 p-2 rounded-full"><User size={20} /></div>
                                    )}
                                    <div>
                                        <div className="font-semibold">{user.name}</div>
                                        {user.phone && <div className="text-xs text-gray-500">{user.phone}</div>}
                                    </div>
                                </td>
                                <td className="p-4 text-gray-600">
                                    {user.email}
                                    {user.qualification && <div className="text-xs text-gray-400 mt-1">{user.qualification}</div>}
                                </td>
                                {!role && (
                                    <td className="p-4">
                                        <span className={`px-2 py-1 rounded-full text-xs font-bold flex items-center gap-1 w-fit ${user.role === 'admin' ? 'bg-purple-100 text-purple-800' :
                                            user.role === 'staff' ? 'bg-blue-100 text-blue-800' : 'bg-gray-100 text-gray-800'
                                            }`}>
                                            {user.role === 'admin' && <Shield size={12} />}
                                            {user.role}
                                        </span>
                                    </td>
                                )}
                                <td className="p-4 flex gap-2">
                                    {(user.role === 'staff' || user.role === 'admin') && (
                                        <button onClick={() => handleEdit(user)} className="text-blue-600 hover:text-blue-800" title="Edit User">
                                            <Edit size={18} />
                                        </button>
                                    )}
                                    {user.role !== 'admin' && (
                                        <button onClick={() => handleDelete(user.id)} className="text-red-600 hover:text-red-800" title="Delete User">
                                            <Trash2 size={18} />
                                        </button>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {users.length === 0 && <div className="p-8 text-center text-gray-500">No {role || 'users'} found.</div>}
            </div>

            {/* Edit Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white p-6 rounded-lg w-full max-w-md">
                        <h3 className="text-xl font-bold mb-4">Edit {currentUser?.role}</h3>
                        <form onSubmit={handleUpdate} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium mb-1">Name</label>
                                <input
                                    type="text"
                                    className="w-full p-2 border rounded"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium mb-1">Qualification</label>
                                <input
                                    type="text"
                                    className="w-full p-2 border rounded"
                                    value={formData.qualification}
                                    onChange={e => setFormData({ ...formData, qualification: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium mb-1">Profile Photo</label>
                                <input
                                    type="file"
                                    accept="image/*"
                                    className="w-full p-2 border rounded bg-gray-50"
                                    onChange={e => setFormData({ ...formData, file: e.target.files[0] })}
                                />
                                {formData.profileImage && !formData.file && (
                                    <div className="mt-2 text-xs text-gray-500">Current photo available</div>
                                )}
                            </div>
                            <div className="flex gap-2 justify-end mt-6">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded">Cancel</button>
                                <button type="submit" disabled={uploading} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50">
                                    {uploading ? 'Saving...' : 'Save Changes'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

