                                    <BookOpen size={120} />
                                </div>
                                <div className="relative z-10">
                                    <h3 className="text-3xl font-black tracking-tight">Course Proposal</h3>
                                    <p className="text-blue-100 text-xs font-bold uppercase tracking-widest mt-2">Curriculum Submission Portal</p>
